SELECT
    b.id,
    b.overtime_start_time clockIn,
    b.overtime_end_time clockOut
FROM
    check_work_overtime a,
    check_work_overtime_time_slot b
WHERE
    a.create_id = #{createId}
  AND a.id = b.parent_id
  AND b.state = #{childState}
  AND b.overtime_day = #{overtimeDay}

    AND a.tenant_id = #{tenantId} AND b.tenant_id = #{tenantId}

SELECT a.id, '加班' title, a.overtime_day 'start', a.overtime_day 'end' FROM check_work_overtime_time_slot a, check_work_overtime b WHERE b.create_id = #{userId} AND b.id = a.parent_id AND a.state = 'pass'
#{month}
AND a.tenant_id = #{tenantId} AND b.tenant_id = #{tenantId}
